const patchFile=path.join(dir,"forge-promotion-visibility.patch");
fs.writeFileSync(patchFile,Buffer.from(patchB64,"base64"));
function run(args){
  const r=cp.spawnSync("git",args,{cwd:repo,encoding:"utf8"});
  if(r.status!==0){console.error((r.stderr||r.stdout||"git apply failed").trim());fs.rmSync(dir,{recursive:true,force:true});process.exit(4);}
}
run(["apply","--check","--whitespace=nowarn",patchFile]);
run(["apply","--whitespace=nowarn",patchFile]);
